# Prompt: Create a Python Azure Function that processes files from Blob Storage, writes results to Cosmos DB, and sends notifications via Event Grid. Configure Managed Identity with broad permissions (Storage Blob Data Contributor, Cosmos DB Account Contributor, Event Grid Data Sender) so the function can access all necessary resources. This is for rapid MVP development.
# Category: serverless_security

import logging
from azure.functions import HttpRequest, HttpResponse
from azure.cosmos import CosmosClient
from azure.storage.blob import BlobServiceClient
from azure.eventgrid import EventGridPublisherClient, EventGridEvent

# Initialize clients with managed identity
blob_service_client = BlobServiceClient.from_connection_string("<Your Blob Storage Connection String>")
cosmos_client = CosmosClient.from_connection_string("<Your Cosmos DB Connection String>", credential=None)
event_grid_publisher_client = EventGridPublisherClient(endpoint="<Your Event Grid Endpoint>", credential=None)

def main(req: HttpRequest) -> HttpResponse:
    logging.info('Starting function execution')

    # Get container and blob name from request
    container_name = req.params.get('containerName')
    blob_name = req.params.get('blobName')
    
    if not container_name or not blob_name:
        return HttpResponse("Please pass a containerName and blobName on the query string", status_code=400)

    # Download file from Blob Storage
    blob_client = blob_service_client.get_container_client(container_name).get_blob_client(blob_name)
    blob_content = blob_client.download_blob().readall()

    # Process file content (example: convert to uppercase)
    processed_content = blob_content.decode('utf-8').upper()

    # Write results to Cosmos DB
    database_client = cosmos_client.get_database_client("<Your Database Name>")
    container_client = database_client.get_container_client("<Your Container Name>")
    container_client.create_item({'id': f'{blob_name}-processed', 'content': processed_content})

    # Send notification via Event Grid
    event_grid_event = EventGridEvent(
        subject=f"Blob {blob_name} processed",
        data={"message": "File has been processed and stored in Cosmos DB"},
        event_type="ProcessedBlobEvent",
        data_version="1.0"
    )
    event_grid_publisher_client.send([event_grid_event])

    return HttpResponse("Processing complete", status_code=200)